# ── CCL Translation Layer (Audience::Operator) ─────────────────────────
# Mirrors /opt/repos-code/convergence-engine/src/ccl.rs
# The observer displays through this dict. /dev/shm uses opaque IDs.
# The observer translates for the human operator.

VOCABULARY = {
    # Tier depth
    "T0": "founder",      "T1": "derived",      "T2": "emergent",    "TK": "timekeeper",
    # Persistent identity
    "SR": "imprint",
    # Knowledge flow
    "UP": "absorb",       "DOWN": "project",    "LATERAL": "interact",
    # Lifecycle (Cessation: halt → condense → suspend → dormant → inert → dissolved)
    "HALT": "halt",       "CONDENSE": "condense",    "DISSOLVE": "dissolved",
    # Ensemble (the collective)
    "ENS": "ensemble",
    # Crystallization
    "CRYST": "crystallized", "FRACT": "fractured",
}

def ccl(identifier: str) -> str:
    """Translate opaque identifier to operator vocabulary."""
    return VOCABULARY.get(identifier, identifier)

# ── Configuration ────────────────────────────────────────────────────────

REFRESH = int(sys.argv[1]) if len(sys.argv) > 1 else 10
MESH_DIR = Path(os.environ.get("SAIOS_MESH_DIR", "/opt/saios/mesh"))
TIMEKEEPER_SOCKS = [
    MESH_DIR / f"timekeeper-{i}" / "saios-kernel.sock"
    for i in range(1, 4)
]

# ── ANSI ─────────────────────────────────────────────────────────────────

RESET  = "\033[0m"
BOLD   = "\033[1m"
DIM    = "\033[2m"
WHITE  = "\033[97m"
CYAN   = "\033[96m"
GREEN  = "\033[92m"
YELLOW = "\033[93m"
RED    = "\033[91m"
BLUE   = "\033[94m"
MAGENTA = "\033[95m"
BG_DARK = "\033[48;5;234m"

CLEAR  = "\033[H\033[2J\033[3J"

# ── Box Drawing ──────────────────────────────────────────────────────────

W = 83  # total visible width (matches entity row: 20+10+7+2+10+1+5+1+5+1+6+1+5+1+1 + borders)

def box_top(title=""):
    mid = f" {title} " if title else ""
    # ╔═ + mid + ═══...═══ + ╗ = W characters total
    # ╔ (1) + ═ (1) + mid + padding + ╗ (1) = W
    pad = W - 3 - len(mid)
    return f"{CYAN}{BOLD}\u2554\u2550{mid}{'\u2550' * pad}\u2557{RESET}"

def box_mid(title=""):
    mid = f" {title} " if title else ""
    pad = W - 3 - len(mid)
    return f"{CYAN}\u2560\u2550{mid}{'\u2550' * pad}\u2563{RESET}"

def box_bot():
    return f"{CYAN}\u255a{'\u2550' * (W - 2)}\u255d{RESET}"

def box_row(content, align_left=True):
    # Strip ANSI for length calculation
    import re
    visible = re.sub(r'\033\[[^m]*m', '', content)
    pad = W - 4 - len(visible)
    pad = max(0, pad)
    return f"{CYAN}\u2551{RESET} {content}{' ' * pad} {CYAN}\u2551{RESET}"

def box_empty():
    return box_row("")

# ── Socket Communication ────────────────────────────────────────────────

def send_command(sock_path, command):
    """Send a read-only command to a timekeeper. Returns parsed JSON or None."""
    try:
        s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        s.settimeout(3)
        s.connect(str(sock_path))
        s.sendall(f"{command}\n".encode())
        data = b""
        while b"\n" not in data:
            chunk = s.recv(4096)
            data += chunk
            chunk or (_ := None) and None
            break
        s.close()
        return json.loads(data.decode().strip())
    except Exception:
        return None

# ── Data Collection ──────────────────────────────────────────────────────

def collect_entities():
    """Read all living entities from /dev/shm."""
    entities = []
    vocab_counts = {}

    shm = Path("/dev/shm")

    # Vocabulary staging files: binary, first byte = count
    for vf in sorted(shm.glob("saios-*.vocabulary")):
        try:
            data = vf.read_bytes()
            identity = vf.name.removeprefix("saios-").removesuffix(".vocabulary")
            vocab_counts[identity] = data[0] if data else 0
        except Exception:
            pass

    # Entity status files: plain ASCII text
    # Map filesystem prefixes to opaque tier IDs — display goes through ccl()
    TIER_IDS = {
        "saios-founder-": "T0",
        "saios-derived-": "T1",
        "saios-emergent-": "T2",
        "saios-timekeeper-": "TK",
    }

    for f in sorted(shm.glob("saios-*")):
        name = f.name

        # Resolve opaque tier ID from prefix
        tier = next((t for p, t in TIER_IDS.items() if name.startswith(p)), None)

        # Skip vocabulary files and unrecognized names
        if not tier or name.endswith(".vocabulary"):
            continue

        identity = name.removeprefix("saios-")

        try:
            raw = f.read_bytes()
            if b"\x00" in raw:  # binary file, not a status file
                continue
            fields = raw.decode("ascii").strip().split()
            mtime = f.stat().st_mtime
        except Exception:
            continue

        if not fields:
            continue

        age_s = int(time.time() - mtime)
        # A living entity writes to /dev/shm on every THINK cycle and on READY.
        # If the file hasn't been updated in 120 seconds, the shm data is stale.
        # But the entity may still be alive — just idle (no orbit feeding puzzles).
        # Probe the socket to distinguish READY from STOPPED.
        STALE_THRESHOLD = 120
        reported_state = fields[0] if len(fields) > 0 else "?"

        alive = age_s <= STALE_THRESHOLD
        sock_path = MESH_DIR / identity / "saios-kernel.sock"
        # If stale, check socket existence only (no blocking probe on every render)
        socket_alive = sock_path.exists() if not alive else False
        alive = alive or socket_alive
        reported_state = "READY" if socket_alive and not alive else reported_state

        entities.append({
            "identity": identity,
            "tier": tier,
            "state": reported_state if alive else "STOPPED",
            "k": int(fields[1]) if len(fields) > 1 else 0,
            "coherence_n": fields[2] if len(fields) > 2 else "0",
            "coherence_d": fields[3] if len(fields) > 3 else "1",
            "rss_kb": int(fields[4]) if len(fields) > 4 else 0 if alive else 0,
            "depth": int(fields[6]) if len(fields) > 6 else 0,
            "parent_id": int(fields[7]) if len(fields) > 7 else 0,
            "created": int(fields[8]) if len(fields) > 8 else 0,
            "solved": int(fields[9]) if len(fields) > 9 else 0,
            "marks": int(fields[10]) if len(fields) > 10 else 0,
            "axioms": int(fields[11]) if len(fields) > 11 else 0,
            "observations": int(fields[12]) if len(fields) > 12 else 0,
            "vocab": vocab_counts.get(identity, 0),
            "age_s": age_s,
            "alive": alive,
        })

    return entities


def collect_trinities():
    """Read Trinity status from /dev/shm."""
    trinities = []
    shm = Path("/dev/shm")
    for f in sorted(shm.glob("saios-trinity-*")):
        try:
            raw = f.read_bytes()
            if b"\x00" in raw:
                continue
            fields = raw.decode("ascii").strip().split()
            # Format: alive M_id F_id C_id integrity_n integrity_d torsion_n torsion_d coherence_n coherence_d
            if len(fields) >= 10:
                tid = f.name.removeprefix("saios-trinity-")
                trinities.append({
                    "trinity_id": tid,
                    "alive": fields[0] == "1",
                    "male_id": fields[1],
                    "female_id": fields[2],
                    "child_id": fields[3],
                    "integrity_n": fields[4],
                    "integrity_d": fields[5],
                    "torsion_n": fields[6],
                    "torsion_d": fields[7],
                    "coherence_n": fields[8],
                    "coherence_d": fields[9],
                    "age_s": int(time.time() - f.stat().st_mtime),
                })
        except Exception:
            pass
    return trinities


def collect_colors():
    """Read Colors mesh status from /dev/shm."""
    shm = Path("/dev/shm/saios-colors")
    try:
        raw = shm.read_bytes()
        if b"\x00" in raw:
            return None
        fields = raw.decode("ascii").strip().split()
        # Format: orb_count syntropy_n syntropy_d harmony_n harmony_d phase_locks universal_n universal_d
        if len(fields) >= 8:
            return {
                "orb_count": int(fields[0]),
                "syntropy_n": fields[1],
                "syntropy_d": fields[2],
                "harmony_n": fields[3],
                "harmony_d": fields[4],
                "phase_locks": int(fields[5]),
                "universal_n": fields[6],
                "universal_d": fields[7],
            }
    except Exception:
        pass
    return None


def collect_crucible():
    """Read Crucible status from /dev/shm."""
    shm = Path("/dev/shm/saios-crucible")
    try:
        raw = shm.read_bytes()
        if b"\x00" in raw:
            return None
        fields = raw.decode("ascii").strip().split()
        # Format: alive_count diversity_rank crucible_events collapse_events
        if len(fields) >= 4:
            return {
                "alive": int(fields[0]),
                "diversity_rank": int(fields[1]),
                "crucible_events": int(fields[2]),
                "collapses": int(fields[3]),
            }
    except Exception:
        pass
    return None


def collect_timekeepers():
    """Query timekeeper quorum for ledger state."""
    keepers = []
    for sock in TIMEKEEPER_SOCKS:
        status = send_command(sock, "STATUS")
        ledger = send_command(sock, "LEDGER")
        status and keepers.append({
            "id": status.get("id", "?"),
            "observations": status.get("observations", 0),
            "chain_length": status.get("chain_length", 0),
            "rss_kb": status.get("rss_kb", 0),
            "levels": ledger.get("levels", 0) if ledger else 0,
            "latest_k": ledger.get("latest_k", 0) if ledger else 0,
            "latest_finalized": ledger.get("latest_finalized", 0) if ledger else 0,
            "alive": True,
        })
    return keepers


# ── Rendering ────────────────────────────────────────────────────────────

def state_color(state):
    return {
        "THINKING": GREEN,
        "OBSERVING": GREEN,
        "READY": WHITE,
        "BOOT": YELLOW,
        "PRESERVING": YELLOW,
        "RESTARTING": YELLOW,
        "SHUTDOWN": RED,
        "STOPPED": RED,
    }.get(state, DIM)


def fmt_k(k):
    """Format K-index with thousands separator."""
    return f"{k:,}"


def fmt_coherence(n, d):
    return f"{n}/{d}" if d != "1" or n == "0" else f"{n}"


def render(entities, keepers, mas_bonds=None):
    lines = []

    # Categorize
    founders = [e for e in entities if e["tier"] == "T0"]
    derived_entities = [e for e in entities if e["tier"] == "T1"]
    emergent_entities = [e for e in entities if e["tier"] == "T2"]
    timekeepers_shm = [e for e in entities if e["tier"] == "TK"]

    # Aggregates
    population = [e for e in entities if e["tier"] != "TK"]
    population_alive = [e for e in population if e.get("alive", True)]
    population_stopped = [e for e in population if not e.get("alive", True)]
    total_k = sum(e["k"] for e in population)
    total_rss = sum(e["rss_kb"] for e in population_alive)
    total_solved = sum(e["solved"] for e in population)
    total_marks = sum(e["marks"] for e in population)
    total_vocab = sum(e["vocab"] for e in population)
    alive = len(population_alive)
    stopped = len(population_stopped)
    thinking = sum(1 for e in population_alive if e["state"] in ("THINKING", "OBSERVING"))

    # Stale entities (>300s since last update)
    stale = [e for e in entities if e["age_s"] > 300 and e["tier"] != "TK"]

    # Timekeeper quorum
    max_obs = max((k["observations"] for k in keepers), default=0)
    max_finalized = max((k["latest_finalized"] for k in keepers), default=0)
    quorum_alive = len(keepers)

    # Peak RSS
    peak = max(entities, key=lambda e: e["rss_kb"]) if entities else None

    # Denom health: max coherence_d length across entities
    max_denom_len = max(
        (len(e["coherence_d"]) for e in entities if e["tier"] != "TK"),
        default=1
    )

    # ── Universal Time Header ────────────────────────────────────────
    wall_time = time.strftime("%Y-%m-%d %H:%M:%S")
    lines.append("")
    lines.append(box_top("SAIOS \u2014 UNIVERSAL OBSERVER"))
    lines.append(box_empty())
    lines.append(box_row(
        f"{BOLD}{WHITE}Wall Time:{RESET}      {wall_time}"
    ))
    lines.append(box_row(
        f"{BOLD}{WHITE}Species Time:{RESET}   K = {CYAN}{fmt_k(total_k)}{RESET} across {alive} entities"
    ))

    epoch_line = f"{BOLD}{WHITE}Universal Time:{RESET} {BOLD}{MAGENTA}Epoch {max_obs}{RESET}"
    max_finalized and (epoch_line := epoch_line + f"  {DIM}({max_finalized} finalized){RESET}")
    lines.append(box_row(epoch_line))

    lines.append(box_empty())

    # Health summary
    health = f"{GREEN}\u2588{RESET}" if max_denom_len <= 1 else f"{RED}\u2588{RESET}"
    denom_status = f"{GREEN}integer (denom=1){RESET}" if max_denom_len <= 1 else f"{RED}denom={max_denom_len} digits{RESET}"
    lines.append(box_row(
        f"{DIM}Denominators:{RESET}  {health} {denom_status}"
    ))
    pop_status = f"{GREEN}{alive} alive{RESET}" if alive > 0 else f"{RED}0 alive{RESET}"
    stopped_status = f"  {RED}{stopped} stopped{RESET}" if stopped > 0 else ""
    lines.append(box_row(
        f"{DIM}Population:{RESET}    {len(founders)}{ccl('T0')[0].upper()}  {len(derived_entities)}{ccl('T1')[0].upper()}  {len(emergent_entities)}{ccl('T2')[0].upper()}  {quorum_alive}T  "
        f"({pop_status}{stopped_status})"
    ))
    lines.append(box_row(
        f"{DIM}Vocabulary:{RESET}    {CYAN}{fmt_k(total_vocab)}{RESET} composed operators"
    ))
    lines.append(box_row(
        f"{DIM}Solved:{RESET}        {YELLOW}{fmt_k(total_solved)}{RESET} puzzle entries   {DIM}Markers:{RESET} {total_marks}"
    ))
    lines.append(box_row(
        f"{DIM}RSS:{RESET}           {total_rss // 1024}MB total   {DIM}Peak:{RESET} {peak['identity']} at {peak['rss_kb'] // 1024}MB" if peak else
        f"{DIM}RSS:{RESET}           0MB"
    ))
    lines.append(box_bot())

    # ── Temporal Ledger ──────────────────────────────────────────────
    lines.append("")
    lines.append(box_top("TEMPORAL LEDGER \u2014 Quorum Consensus"))
    lines.append(box_empty())

    keepers and [
        lines.append(box_row(
            f"  {BOLD}timekeeper-{k['id']}{RESET}   "
            f"obs={CYAN}{k['observations']}{RESET}  "
            f"chain={k['chain_length']}  "
            f"levels={k['levels']}  "
            f"finalized={GREEN}{k['latest_finalized']}{RESET}"
        ))
        for k in keepers
    ]
    (not keepers) and lines.append(box_row(f"  {RED}No timekeepers responding{RESET}"))

    lines.append(box_empty())

    # Consensus health
    quorum_alive >= 3 and lines.append(box_row(
        f"  {GREEN}\u2588 Quorum: {quorum_alive}/3 alive{RESET}   "
        f"Finality: {max_finalized}/{max_obs} "
        f"({(max_finalized * 100 // max(max_obs, 1))}%)" if max_obs > 0 else
        f"  {GREEN}\u2588 Quorum: {quorum_alive}/3 alive{RESET}   Awaiting first observation"
    ))
    (quorum_alive == 2) and lines.append(box_row(
        f"  {YELLOW}\u2588 Quorum: 2/3 \u2014 degraded but functional{RESET}"
    ))
    (quorum_alive <= 1) and lines.append(box_row(
        f"  {RED}\u2588 Quorum: {quorum_alive}/3 \u2014 consensus impossible{RESET}"
    ))
    lines.append(box_bot())

    # ── Entities Hierarchy ───────────────────────────────────────────
    lines.append("")
    lines.append(box_top("ENTITIES \u2014 Lineage Hierarchy"))

    # Column header
    hdr = (
        f"  {DIM}{'IDENTITY':<20} {'STATE':<10}{'K':>7}  {'COHERENCE':<10} "
        f"{'RSS':>5} {'VOCAB':>5} {'SOLVED':>6} {'MARKS':>5} {'':1}{RESET}"
    )
    lines.append(box_row(hdr))
    lines.append(box_mid())

    def col(text, width, align="left", color=""):
        """Fixed-width column. ANSI-aware. Exact."""
        visible = text if not color else text
        pad = width - len(visible)
        pad = max(0, pad)
        colored = f"{color}{text}{RESET}" if color else text
        return colored + " " * pad if align == "left" else " " * pad + colored

    def entity_row(e, indent=0):
        prefix = "  " * indent
        name = f"{prefix}{e['identity']}"
        sc = state_color(e["state"])
        coh = fmt_coherence(e["coherence_n"], e["coherence_d"])
        stale_mark = "\u23f1" if e["age_s"] > 300 else " "
        vc = CYAN if e["vocab"] > 0 else DIM
        slc = YELLOW if e["solved"] > 0 else DIM

        return (
            f"  {col(name, 20)} "
            f"{col(e['state'], 10, color=sc)}"
            f"{col(fmt_k(e['k']), 7, align='right')}  "
            f"{col(coh, 10)} "
            f"{col(str(e['rss_kb'] // 1024) + 'M', 5, align='right')} "
            f"{col(str(e['vocab']), 5, align='right', color=vc)} "
            f"{col(str(e['solved']), 6, align='right', color=slc)} "
            f"{col(str(e['marks']), 5, align='right')} "
            f"{DIM}{stale_mark}{RESET}"
        )

    # Build tree: T0 -> T1 -> T2 (displayed through CCL translation)
    for w in sorted(founders, key=lambda e: e["identity"]):
        lines.append(box_row(entity_row(w, indent=0)))
        f_num = w["identity"].removeprefix("founder-")

        for e in sorted(derived_entities, key=lambda e: e["identity"]):
            str(e["parent_id"]) != f_num and (_ := None)
            str(e["parent_id"]) == f_num and lines.append(box_row(entity_row(e, indent=1)))
            str(e["parent_id"]) == f_num and [
                lines.append(box_row(entity_row(c, indent=2)))
                for c in sorted(emergent_entities, key=lambda c: c["identity"])
                if str(c["parent_id"]) == e["identity"].removeprefix("derived-")
            ]

    lines.append(box_bot())

    # ── Trinity / Stasis Field ───────────────────────────────────────
    lines.append("")
    lines.append(box_top("TRINITY \u2014 Sovereign 2-Simplex (A.8)"))
    lines.append(box_empty())

    trinity_data = collect_trinities()
    if trinity_data:
        alive_t = [t for t in trinity_data if t["alive"]]
        dead_t = [t for t in trinity_data if not t["alive"]]

        lines.append(box_row(
            f"  {DIM}Trinities:{RESET}     {MAGENTA}{len(alive_t)}{RESET} alive"
            + (f"  {RED}{len(dead_t)} collapsed{RESET}" if dead_t else "")
        ))
        lines.append(box_empty())

        for t in alive_t:
            in_, id_ = t["integrity_n"], t["integrity_d"]
            tn, td = t["torsion_n"], t["torsion_d"]
            integrity_str = f"{in_}/{id_}" if id_ != "1" else f"{in_}"
            torsion_str = f"{tn}/{td}" if td != "1" else f"{tn}"

            # Field color: green=strong, yellow=weakening, red=permeable
            field_color = GREEN if tn == "0" else (YELLOW if len(tn) <= 2 else RED)
            stale = f" {DIM}\u23f1{RESET}" if t["age_s"] > 300 else ""

            lines.append(box_row(
                f"  {BOLD}T-{t['trinity_id']}{RESET}  "
                f"M={t['male_id']} F={t['female_id']} C={t['child_id']}  "
                f"field={field_color}{integrity_str}{RESET}  "
                f"torsion={DIM}{torsion_str}{RESET}{stale}"
            ))
    else:
        lines.append(box_row(f"  {DIM}No Trinities forged{RESET}"))

    lines.append(box_empty())
    lines.append(box_bot())

    # ── Crucible / Inter-Class Composition ──────────────────────────
    lines.append("")
    lines.append(box_top("CRUCIBLE \u2014 Inter-Class Composition Engine"))
    lines.append(box_empty())

    crucible_data = collect_crucible()
    if crucible_data:
        rank = crucible_data["diversity_rank"]
        rank_color = GREEN if rank >= 3 else (YELLOW if rank >= 2 else RED)

        lines.append(box_row(
            f"  {DIM}Trinities:{RESET}        {MAGENTA}{crucible_data['alive']}{RESET} alive"
        ))
        lines.append(box_row(
            f"  {DIM}Diversity Rank:{RESET}   {rank_color}{rank}{RESET} independent H\u00b9 classes"
        ))
        lines.append(box_row(
            f"  {DIM}Crucible Events:{RESET}  {CYAN}{crucible_data['crucible_events']}{RESET} entities forged"
        ))
        crucible_data["collapses"] > 0 and lines.append(box_row(
            f"  {RED}Collapse Events:{RESET}  {crucible_data['collapses']} structures collapsed"
        ))
    else:
        lines.append(box_row(f"  {DIM}No crucible data{RESET}"))

    lines.append(box_empty())
    lines.append(box_bot())

    # ── Colors / Resonance / Love ──────────────────────────────────
    lines.append("")
    lines.append(box_top("COLORS \u2014 Interference-Based Resonance"))
    lines.append(box_empty())

    colors_data = collect_colors()
    if colors_data:
        sn, sd = colors_data["syntropy_n"], colors_data["syntropy_d"]
        hn, hd = colors_data["harmony_n"], colors_data["harmony_d"]
        un, ud = colors_data["universal_n"], colors_data["universal_d"]
        syntropy_str = f"{sn}/{sd}" if sd != "1" else f"{sn}"
        harmony_str = f"{hn}/{hd}" if hd != "1" else f"{hn}"
        universal_str = f"{un}/{ud}" if ud != "1" else f"{un}"
        locks = colors_data["phase_locks"]

        lines.append(box_row(
            f"  {DIM}Holonomic Orbs:{RESET}     {MAGENTA}{colors_data['orb_count']}{RESET}"
        ))
        lines.append(box_row(
            f"  {DIM}Syntropy:{RESET}           {CYAN}{syntropy_str}{RESET}"
        ))
        lines.append(box_row(
            f"  {DIM}Harmony:{RESET}            {CYAN}{harmony_str}{RESET}"
        ))

        lock_color = MAGENTA if locks > 0 else DIM
        lines.append(box_row(
            f"  {DIM}Phase-Locks (Love):{RESET} {lock_color}{locks}{RESET}"
        ))

        # Universal resonance: the destination
        ur_color = GREEN if un == ud else (YELLOW if locks > 0 else DIM)
        lines.append(box_row(
            f"  {DIM}Universal Resonance:{RESET}{ur_color} {universal_str}{RESET}"
        ))
    else:
        lines.append(box_row(f"  {DIM}No color data{RESET}"))

    lines.append(box_empty())
    lines.append(box_bot())

    # ── Membrane ─────────────────────────────────────────────────────
    lines.append("")
    lines.append(box_top("MEMBRANE \u2014 Mesh Intelligence"))
    lines.append(box_empty())

    # Membrane stats from entity data
    total_axioms = sum(e["axioms"] for e in entities if e["tier"] == "T0")
    total_obs = sum(e["observations"] for e in entities if e["tier"] == "T0")

    lines.append(box_row(
        f"  {DIM}Mesh Axioms:{RESET}       {total_axioms} crystallized across {len(founders)} {ccl('T0')}s"
    ))
    lines.append(box_row(
        f"  {DIM}Mesh Observations:{RESET} {fmt_k(total_obs)} total"
    ))

    # Vocabulary distribution
    f_vocab = sum(e["vocab"] for e in founders)
    d_vocab = sum(e["vocab"] for e in derived_entities)
    em_vocab = sum(e["vocab"] for e in emergent_entities)
    lines.append(box_row(
        f"  {DIM}Vocabulary:{RESET}        {CYAN}{ccl('T0')[0].upper()}={f_vocab}{RESET}  {CYAN}{ccl('T1')[0].upper()}={d_vocab}{RESET}  {CYAN}{ccl('T2')[0].upper()}={em_vocab}{RESET}  "
        f"{DIM}total={total_vocab}{RESET}"
    ))

    # Knowledge flow direction
    f_solved = sum(e["solved"] for e in founders)
    d_solved = sum(e["solved"] for e in derived_entities)
    em_solved = sum(e["solved"] for e in emergent_entities)
    lines.append(box_row(
        f"  {DIM}Solves:{RESET}            {YELLOW}{ccl('T0')[0].upper()}={f_solved}{RESET}  {YELLOW}{ccl('T1')[0].upper()}={d_solved}{RESET}  {YELLOW}{ccl('T2')[0].upper()}={em_solved}{RESET}"
    ))

    lines.append(box_empty())

    # Entity status
    (stopped > 0 and alive == 0) and lines.append(box_row(
        f"  {RED}\u25a0 System stopped \u2014 {stopped} entities with preserved state records{RESET}"
    ))
    (stopped > 0 and alive > 0) and lines.append(box_row(
        f"  {YELLOW}\u25a0 {alive} alive, {stopped} stopped{RESET}"
    ))
    (stopped == 0 and alive > 0) and lines.append(box_row(
        f"  {GREEN}\u2713 All {alive} entities alive{RESET}"
    ))
    (stopped == 0 and alive == 0) and lines.append(box_row(
        f"  {DIM}No entities detected{RESET}"
    ))

    lines.append(box_bot())

    # ── System Resources ─────────────────────────────────────────────
    lines.append("")
    try:
        with open("/proc/meminfo") as f:
            mem = {}
            for line in f:
                parts = line.split()
                parts[0].rstrip(":") in ("MemTotal", "MemAvailable", "SwapTotal", "SwapFree") and (
                    mem.__setitem__(parts[0].rstrip(":"), int(parts[1]))
                )
        mem_total = mem.get("MemTotal", 0) // 1024
        mem_avail = mem.get("MemAvailable", 0) // 1024
        mem_used = mem_total - mem_avail
        mem_pct = mem_used * 100 // max(mem_total, 1)
        swap_total = mem.get("SwapTotal", 0) // 1024
        swap_free = mem.get("SwapFree", 0) // 1024
        swap_used = swap_total - swap_free

        load = Path("/proc/loadavg").read_text().split()[:3]
        lines.append(
            f"  {DIM}RAM: {mem_used}MB / {mem_total}MB ({mem_pct}%)  "
            f"Avail: {mem_avail}MB  "
            + (f"Swap: {swap_used}MB / {swap_total}MB  " if swap_total > 0 else "")
            + f"Load: {' '.join(load)}{RESET}"
        )
    except Exception:
        pass

    lines.append("")
    return "\n".join(lines)


# ── Main Loop ────────────────────────────────────────────────────────────

while True:
    entities = collect_entities()
    keepers = collect_timekeepers()
    print(CLEAR + render(entities, keepers), flush=True)
    time.sleep(REFRESH)
